    git(
        &[
            "-c",
            "user.name=SIFS Test",
            "-c",
            "user.email=sifs@example.com",
            "commit",
            "-m",
            "main",
        ],
        repo.path(),
    );
    git(&["checkout", "-b", "feature-ref"], repo.path());
    fs::write(
        repo.path().join("lib.rs"),
        "fn feature_branch_marker() {}\n",
    )
