    git(
        &[
            "-c",
            "user.name=SIFS Test",
            "-c",
            "user.email=sifs@example.com",
            "commit",
            "-m",
            "feature",
        ],
        repo.path(),
    );
    git(&["checkout", "main"], repo.path());

    let home = tempfile::tempdir().unwrap();
    let source = format!("file://{}", repo.path().display());
    let save = sifs()
        .args([
            "profile",
            "save",
            "git-ref-test",
            "--source",
            &source,
            "--ref",
            "feature-ref",
            "--mode",
            "bm25",
            "--no-cache",
            "--json",
        ])
        .env("HOME", home.path())
        .output()
        .unwrap();
    assert!(
        save.status.success(),
        "stderr: {}",
        String::from_utf8_lossy(&save.stderr)
    );

    let search = sifs()
        .args([
            "search",
            "feature_branch_marker",
            "--profile",
            "git-ref-test",
            "--json",
        ])
        .env("HOME", home.path())
        .output()
        .unwrap();
    assert!(
        search.status.success(),
        "stderr: {}",
        String::from_utf8_lossy(&search.stderr)
    );
    let searched: Value = serde_json::from_slice(&search.stdout).unwrap();
    let results = searched["results"].as_array().unwrap();
    assert!(!results.is_empty());
    assert!(results.iter().any(|result| {
        result["content"]
            .as_str()
            .unwrap()
            .contains("feature_branch_marker")
    }));
}

